1	import { Controller, Get, Param, Query } from '@nestjs/common';
2	import { ApiOperation, ApiParam, ApiResponse, ApiTags } from '@nestjs/swagger';
3	
4	import { MetricsService } from '@modules/metrics/metrics.service';
5	import { RelatedProductsService } from '@modules/rest/related-products/related-products.service';
6	
7	import { dailyTrackingKeys } from '@constants/common.constant';
8	
9	import { LogExecution } from '@decorators/log-execution.decorator';
10	
11	import { BrandProductsQueryDto } from '@dto/brand-products/brand-products-query.dto';
12	import { BrandProductsResponseDto } from '@dto/brand-products/brand-products-response.dto';
13	import { RelatedProductsQueryDto } from '@dto/related-products/related-products-query.dto';
14	import { RelatedProductsResponseDto } from '@dto/related-products/related-products-response.dto';
15	
16	@ApiTags('Related Products')
17	@Controller('related-products')
18	export class RelatedProductsController {
19		constructor(
20			private readonly relatedProductsService: RelatedProductsService,
21			private readonly metricsService: MetricsService,
22		) {}
23	
24		@Get('brand')
25		@ApiOperation({ summary: 'Get products for a specific brand' })
26		@ApiResponse({
27			status: 200,
28			description: 'Returns products for the specified brand',
29			type: BrandProductsResponseDto,
30		})
31		@ApiResponse({ status: 404, description: 'Brand not found' })
32		@ApiResponse({ status: 500, description: 'Internal server error' })
33		@LogExecution({
34			paramFormatter: ([query]: [BrandProductsQueryDto]) => ({
35				brand: query.brand,
36				styleId: query.styleId,
37				colorId: query.colorId,
38				limit: query.limit,
39				sortBy: query.sortBy,
40			}),
41			responseFormatter: (res: BrandProductsResponseDto) => ({
42				count: res?.brand_products?.length ?? 0,
43			}),
44		})
45		async getBrandProducts(
46			@Query() query: BrandProductsQueryDto,
47		): Promise<BrandProductsResponseDto> {
48			return await this.relatedProductsService.getBrandProducts(query);
49		}
50	
51		@Get(':productId')
52		@ApiOperation({ summary: 'Get related products for a specific product ID' })
53		@ApiParam({ name: 'productId', type: String, description: 'Product ID' })
54		@ApiResponse({
55			status: 200,
56			description: 'Returns related products for the specified product ID',
57			type: RelatedProductsResponseDto,
58		})
59		@ApiResponse({ status: 404, description: 'Product not found' })
60		@ApiResponse({ status: 500, description: 'Internal server error' })
61		@LogExecution({
62			paramFormatter: (params: [string, RelatedProductsQueryDto]) => ({
63				productId: params[0],
64				query: params[1],
65			}),
66			responseFormatter: (response: RelatedProductsResponseDto) => ({
67				relatedProducts: response.related_products.map((prod) => prod.style_id),
68				productId: response.product_id,
69				mmsFallback: response.mms_fallback,
70				colorId: response.color_id,
71			}),
72		})
73		async getRelatedProducts(
74			@Param('productId') productId: string,
75			@Query() query: RelatedProductsQueryDto,
76		): Promise<RelatedProductsResponseDto> {
77			await this.metricsService.incrementDailyCounter({
78				metricType: dailyTrackingKeys.RELATED_PRODUCTS_REQUESTS,
79			});
80			return this.relatedProductsService.getRelatedProducts({ productId, query });
81		}
82	}
