8		@ApiProperty({
9			description: 'Product ID for which related products are returned',
10			example: '56789',
11		})
12		product_id: string;
13	
14		@ApiProperty({
15			description: 'List of related products',
16			type: [RelatedProductDto],
17		})
18		brand_products: IRelatedProduct[];
19	
20		@ApiProperty({
21			description: 'Color ID used to filter related products',
22			example: 12345,
23		})
24		color_id: number | null;
25	
26		@ApiProperty({
27			description: 'Brand name used to filter related products',
28			example: 'Nike',
29		})
30		brand: string;
31	
32		@ApiProperty({
33			description: 'Sort by',
34			example: 'category',
35		})
36		sort_by: 'category' | 'rating' | null;
37	}
